import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  Input,
  OnChanges,
  ViewChild,
} from '@angular/core';
import type { TypeIconSize, TypeIconSizeName, TypeIconVariant } from './types';

@Component({
  selector: 'fn-icon',
  standalone: true,
  imports: [CommonModule],
  template: `
    <span
      #iconContainer
      [class]="className"
      [style.width.px]="iconSize"
      [style.height.px]="iconSize"
      [style.display]="'block'"
      [style.overflow]="'hidden'"
      [style.color]="color ? color : null"
      [style.opacity]="disabled ? 0.5 : 1"
      [style.cursor]="disabled ? 'not-allowed' : 'inherit'"
    ></span>
  `,
})
export class FNIconComponent implements OnChanges {
  @Input() name!: string; // Icon name without extension
  @Input() variant: TypeIconVariant = 'Line';
  @Input() size: TypeIconSizeName = 'medium';
  @Input() color?: string;
  @Input() strokeWidth?: number; // optional - for line icons
  @Input() disabled: boolean = false;
  @Input() className: string = ''; // CSS class name for Tailwind support
  @Input() basePath: string = 'assets/icons'; // Base path for icon assets

  @ViewChild('iconContainer', { static: true })
  iconContainer!: ElementRef<HTMLElement>;

  // Size mapping
  private readonly sizeMap: Record<TypeIconSizeName, TypeIconSize> = {
    extrasmall: 10,
    small: 16,
    medium: 20,
    large: 24,
    'x-large': 32,
    xxlarge: 48,
  };

  get iconSize(): TypeIconSize {
    return this.sizeMap[this.size];
  }

  constructor(
    private readonly http: HttpClient,
    private readonly cdr: ChangeDetectorRef,
  ) {}

  getIconPath(
    icon: string,
    variant: TypeIconVariant = 'Line',
    size: TypeIconSize = 24,
  ): string | null {
    if (!icon) return null;

    // For size 16 or 10 → normal path
    if (size === 16 || size === 10) {
      return `${this.basePath}/${variant}/${size}px/${icon}.svg`;
    }

    // For 20, 24, ... → add `--{size}` suffix
    return `${this.basePath}/${variant}/${size}px/${icon}--${size}.svg`;
  }

  ngOnChanges(): void {
    if (!this.name) {
      this.clearSvg();
      return;
    }

    const iconPath = this.getIconPath(this.name, this.variant, this.iconSize);
    if (!iconPath) {
      this.clearSvg();
      return;
    }

    this.http.get(iconPath, { responseType: 'text' }).subscribe({
      next: (raw) => this.processSvgRaw(raw),
      error: () => {
        this.clearSvg();
        this.cdr.detectChanges();
      },
    });
  }

  private processSvgRaw(raw: string): void {
    try {
      const parser = new DOMParser();
      const doc = parser.parseFromString(raw, 'image/svg+xml');
      const svg = this.validateSvgDocument(doc);

      if (!svg) {
        this.clearSvg();
        return;
      }

      this.removeStyleElements(svg);
      this.normalizeColors(svg);
      this.configureSvgAttributes(svg);

      this.insertSvg(svg);
      this.cdr.detectChanges();
    } catch (error) {
      console.error(
        `[fn-icon] Error parsing SVG for icon "${this.name}":`,
        error,
      );
      this.clearSvg();
      this.cdr.detectChanges();
    }
  }

  private clearSvg(): void {
    if (this.iconContainer?.nativeElement) {
      this.iconContainer.nativeElement.innerHTML = '';
    }
  }

  private insertSvg(svg: SVGSVGElement): void {
    this.clearSvg();
    if (this.iconContainer?.nativeElement) {
      this.iconContainer.nativeElement.appendChild(svg);
    }
  }

  private validateSvgDocument(doc: Document): SVGSVGElement | null {
    const parserError = doc.querySelector('parsererror');
    if (parserError) {
      return null;
    }

    const svg = doc.documentElement;
    return svg.tagName === 'svg' ? (svg as unknown as SVGSVGElement) : null;
  }

  private removeStyleElements(svg: SVGSVGElement): void {
    Array.from(svg.querySelectorAll('style')).forEach((s) => s.remove());
  }

  private normalizeColors(svg: SVGSVGElement): void {
    if (!this.color) {
      return;
    }

    Array.from(svg.querySelectorAll<SVGElement>('*')).forEach((el) => {
      this.normalizeElementColors(el);
    });
  }

  private normalizeElementColors(el: SVGElement): void {
    this.cleanInlineStyles(el);
    this.normalizeFillAttribute(el);
    this.normalizeStrokeAttribute(el);
    this.applyStrokeWidth(el);
  }

  private cleanInlineStyles(el: SVGElement): void {
    const style = el.getAttribute('style');
    if (!style) {
      return;
    }

    const cleaned = style
      .replace(/fill\s*:\s*[^;]+;?/gi, '')
      .replace(/stroke\s*:\s*[^;]+;?/gi, '');

    if (cleaned) {
      el.setAttribute('style', cleaned);
    } else {
      el.removeAttribute('style');
    }
  }

  private normalizeFillAttribute(el: SVGElement): void {
    const fill = el.getAttribute('fill');
    if (fill && fill !== 'none' && !fill.startsWith('url(')) {
      el.setAttribute('fill', 'currentColor');
    }
  }

  private normalizeStrokeAttribute(el: SVGElement): void {
    const stroke = el.getAttribute('stroke');
    if (stroke && stroke !== 'none' && !stroke.startsWith('url(')) {
      el.setAttribute('stroke', 'currentColor');
    }
  }

  private applyStrokeWidth(el: SVGElement): void {
    if (this.strokeWidth != null && el.hasAttribute('stroke')) {
      el.setAttribute('stroke-width', String(this.strokeWidth));
    }
  }

  private configureSvgAttributes(svg: SVGSVGElement): void {
    svg.removeAttribute('width');
    svg.removeAttribute('height');

    if (!svg.getAttribute('viewBox')) {
      svg.setAttribute('viewBox', `0 0 ${this.iconSize} ${this.iconSize}`);
    }

    svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
    svg.setAttribute('focusable', 'false');
    svg.setAttribute('aria-hidden', 'true');
    svg.setAttribute('width', '100%');
    svg.setAttribute('height', '100%');

    if (svg.style) {
      svg.style.display = 'block';
      svg.style.maxWidth = '100%';
      svg.style.maxHeight = '100%';
    } else {
      let style = svg.getAttribute('style') || '';
      style += ';display:block;max-width:100%;max-height:100%;';
      svg.setAttribute('style', style);
    }
  }
}
